// 교육용 빅뱅 시뮬레이션 - 4단계 동시 표시 형식
import * as THREE from "three";

/**
 * 1️⃣ 쿼크-글루온 플라즈마
 * 극도로 뜨거운 상태 - 중앙 뭉치 + 주변 회전 궤도
 */
export function createStage0_QuarkGluonPlasma() {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // 중앙 뭉치 (100k 입자)
  const coreGeom = new THREE.BufferGeometry();
  const numCore = 100000;
  const corePos = new Float32Array(numCore * 3);
  const coreCol = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * 8;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePos[i * 3 + 2] = r * Math.cos(phi);

    const colorType = Math.floor(Math.random() * 4);
    if (colorType === 0) {
      coreCol[i * 3] = 1.0;
      coreCol[i * 3 + 1] = 0.3;
      coreCol[i * 3 + 2] = 0.3;
    } else if (colorType === 1) {
      coreCol[i * 3] = 0.3;
      coreCol[i * 3 + 1] = 0.5;
      coreCol[i * 3 + 2] = 1.0;
    } else if (colorType === 2) {
      coreCol[i * 3] = 0.3;
      coreCol[i * 3 + 1] = 1.0;
      coreCol[i * 3 + 2] = 0.3;
    } else {
      coreCol[i * 3] = 1.0;
      coreCol[i * 3 + 1] = 1.0;
      coreCol[i * 3 + 2] = 0.3;
    }
  }

  coreGeom.setAttribute("position", new THREE.BufferAttribute(corePos, 3));
  coreGeom.setAttribute("color", new THREE.BufferAttribute(coreCol, 3));

  const coreMat = new THREE.PointsMaterial({
    size: 0.3,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.9
  });

  const corePoints = new THREE.Points(coreGeom, coreMat);
  group.add(corePoints);

  // 3개 궤도
  const orbits = [
    { radius: 30, color: [1.0, 0.3, 0.3], count: 50000 },
    { radius: 50, color: [0.3, 0.5, 1.0], count: 50000 },
    { radius: 70, color: [0.3, 1.0, 0.3], count: 50000 }
  ];

  orbits.forEach((orbit, idx) => {
    const geom = new THREE.BufferGeometry();
    const pos = new Float32Array(orbit.count * 3);
    const col = new Float32Array(orbit.count * 3);

    for (let i = 0; i < orbit.count; i++) {
      const baseAngle = (i / orbit.count) * Math.PI * 2;
      const angle = baseAngle + time * (idx + 0.5);
      const tilt = (idx / 3) * Math.PI * 0.2;

      pos[i * 3] = Math.cos(angle) * orbit.radius;
      pos[i * 3 + 1] = Math.sin(angle) * orbit.radius * Math.cos(tilt);
      pos[i * 3 + 2] = Math.sin(angle) * orbit.radius * Math.sin(tilt);

      col[i * 3] = orbit.color[0];
      col[i * 3 + 1] = orbit.color[1];
      col[i * 3 + 2] = orbit.color[2];
    }

    geom.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    geom.setAttribute("color", new THREE.BufferAttribute(col, 3));

    const mat = new THREE.PointsMaterial({
      size: 0.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.7
    });

    const points = new THREE.Points(geom, mat);
    group.add(points);
  });

  group.userData.isAnimated = true;
  return group;
}

/**
 * 2️⃣ 쿼크 결합 → 양성자/중성자
 * 쿼크들이 결합하기 시작
 */
export function createStage1_QuarkCombination() {
  const group = new THREE.Group();

  // 더 큰 중앙 핵 (쿼크 결합됨)
  const coreGeom = new THREE.BufferGeometry();
  const numCore = 150000;
  const corePos = new Float32Array(numCore * 3);
  const coreCol = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * 12;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePos[i * 3 + 2] = r * Math.cos(phi);

    if (Math.random() > 0.5) {
      coreCol[i * 3] = 1.0;
      coreCol[i * 3 + 1] = 0.3;
      coreCol[i * 3 + 2] = 0.3;
    } else {
      coreCol[i * 3] = 0.3;
      coreCol[i * 3 + 1] = 0.5;
      coreCol[i * 3 + 2] = 1.0;
    }
  }

  coreGeom.setAttribute("position", new THREE.BufferAttribute(corePos, 3));
  coreGeom.setAttribute("color", new THREE.BufferAttribute(coreCol, 3));

  const coreMat = new THREE.PointsMaterial({
    size: 0.4,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.8
  });

  const corePoints = new THREE.Points(coreGeom, coreMat);
  group.add(corePoints);

  // 2개 궤도 (쿼크들이 접근중)
  const orbits = [
    { radius: 25, color: [1.0, 0.5, 0.5], count: 40000 },
    { radius: 40, color: [0.5, 0.7, 1.0], count: 40000 }
  ];

  orbits.forEach((orbit, idx) => {
    const geom = new THREE.BufferGeometry();
    const pos = new Float32Array(orbit.count * 3);
    const col = new Float32Array(orbit.count * 3);

    for (let i = 0; i < orbit.count; i++) {
      const angle = (i / orbit.count) * Math.PI * 2;
      const tilt = (idx / 2) * Math.PI * 0.25;

      pos[i * 3] = Math.cos(angle) * orbit.radius;
      pos[i * 3 + 1] = Math.sin(angle) * orbit.radius * Math.cos(tilt);
      pos[i * 3 + 2] = Math.sin(angle) * orbit.radius * Math.sin(tilt);

      col[i * 3] = orbit.color[0];
      col[i * 3 + 1] = orbit.color[1];
      col[i * 3 + 2] = orbit.color[2];
    }

    geom.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    geom.setAttribute("color", new THREE.BufferAttribute(col, 3));

    const mat = new THREE.PointsMaterial({
      size: 0.25,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.6
    });

    const points = new THREE.Points(geom, mat);
    group.add(points);
  });

  return group;
}

/**
 * 3️⃣ 핵융합 → 원자핵 형성
 * 양성자/중성자가 융합하여 원자핵 형성 (He-4, Li, Be)
 */
export function createStage2_Nucleosynthesis() {
  const group = new THREE.Group();

  // 더 큰 원자핵 (핵융합됨)
  const coreGeom = new THREE.BufferGeometry();
  const numCore = 200000;
  const corePos = new Float32Array(numCore * 3);
  const coreCol = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * 15;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePos[i * 3 + 2] = r * Math.cos(phi);

    const colorType = Math.floor(Math.random() * 3);
    if (colorType === 0) {
      coreCol[i * 3] = 0.2;
      coreCol[i * 3 + 1] = 1.0;
      coreCol[i * 3 + 2] = 1.0;
    } else if (colorType === 1) {
      coreCol[i * 3] = 0.3;
      coreCol[i * 3 + 1] = 1.0;
      coreCol[i * 3 + 2] = 0.3;
    } else {
      coreCol[i * 3] = 1.0;
      coreCol[i * 3 + 1] = 1.0;
      coreCol[i * 3 + 2] = 0.3;
    }
  }

  coreGeom.setAttribute("position", new THREE.BufferAttribute(corePos, 3));
  coreGeom.setAttribute("color", new THREE.BufferAttribute(coreCol, 3));

  const coreMat = new THREE.PointsMaterial({
    size: 0.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.85
  });

  const corePoints = new THREE.Points(coreGeom, coreMat);
  group.add(corePoints);

  // 1개 궤도 (대부분 중심으로 모임)
  const orbitGeom = new THREE.BufferGeometry();
  const orbitPos = new Float32Array(30000 * 3);
  const orbitCol = new Float32Array(30000 * 3);

  for (let i = 0; i < 30000; i++) {
    const angle = (i / 30000) * Math.PI * 2;
    const radius = 20;

    orbitPos[i * 3] = Math.cos(angle) * radius;
    orbitPos[i * 3 + 1] = Math.sin(angle) * radius;
    orbitPos[i * 3 + 2] = Math.sin(angle) * radius * 0.1;

    orbitCol[i * 3] = 1.0;
    orbitCol[i * 3 + 1] = 0.7;
    orbitCol[i * 3 + 2] = 0.5;
  }

  orbitGeom.setAttribute("position", new THREE.BufferAttribute(orbitPos, 3));
  orbitGeom.setAttribute("color", new THREE.BufferAttribute(orbitCol, 3));

  const orbitMat = new THREE.PointsMaterial({
    size: 0.3,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5
  });

  const orbitPoints = new THREE.Points(orbitGeom, orbitMat);
  group.add(orbitPoints);

  return group;
}

/**
 * 4️⃣ 원자 형성 (보어 모델)
 * 작은 원자핵 주변을 전자껍질이 감싸는 구조
 */
export function createStage3_AtomFormation() {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // 매우 작은 원자핵 (중앙)
  const coreGeom = new THREE.BufferGeometry();
  const numCore = 100000;
  const corePos = new Float32Array(numCore * 3);
  const coreCol = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * 3;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePos[i * 3 + 2] = r * Math.cos(phi);

    coreCol[i * 3] = 1.0;
    coreCol[i * 3 + 1] = 1.0;
    coreCol[i * 3 + 2] = 0.3;
  }

  coreGeom.setAttribute("position", new THREE.BufferAttribute(corePos, 3));
  coreGeom.setAttribute("color", new THREE.BufferAttribute(coreCol, 3));

  const coreMat = new THREE.PointsMaterial({
    size: 0.6,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 1.0
  });

  const corePoints = new THREE.Points(coreGeom, coreMat);
  group.add(corePoints);

  // 3개 전자 껍질 (K, L, M)
  const shells = [
    { radius: 20, color: [0.2, 0.8, 1.0], count: 80000 },
    { radius: 40, color: [0.5, 0.9, 1.0], count: 100000 },
    { radius: 60, color: [0.7, 0.95, 1.0], count: 80000 }
  ];

  shells.forEach((shell, shellIdx) => {
    const geom = new THREE.BufferGeometry();
    const pos = new Float32Array(shell.count * 3);
    const col = new Float32Array(shell.count * 3);

    for (let i = 0; i < shell.count; i++) {
      const baseAngle = (i / shell.count) * Math.PI * 2;
      const angle = baseAngle + time * (shellIdx + 1) * 0.3;
      const tilt = (i / shell.count) * Math.PI * 0.3;

      pos[i * 3] = Math.cos(angle) * shell.radius;
      pos[i * 3 + 1] = Math.sin(angle) * shell.radius * Math.cos(tilt);
      pos[i * 3 + 2] = Math.sin(angle) * shell.radius * Math.sin(tilt);

      col[i * 3] = shell.color[0];
      col[i * 3 + 1] = shell.color[1];
      col[i * 3 + 2] = shell.color[2];
    }

    geom.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    geom.setAttribute("color", new THREE.BufferAttribute(col, 3));

    const mat = new THREE.PointsMaterial({
      size: 0.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.7
    });

    const points = new THREE.Points(geom, mat);
    group.add(points);
  });

  group.userData.isAnimated = true;
  return group;
}

// 단계 정보
export const educationalBigBangStages = [
  {
    id: 0,
    name: "쿼크-글루온 플라즈마",
    timeRange: "10⁻¹² 초",
    description: "우주 극초기 - 극도로 뜨거운 상태"
  },
  {
    id: 1,
    name: "양성자/중성자 형성",
    timeRange: "10⁻⁶ 초",
    description: "쿼크들이 결합하기 시작"
  },
  {
    id: 2,
    name: "핵융합 → 원자핵",
    timeRange: "1-3 분",
    description: "헬륨-4, 리튬 등 형성"
  },
  {
    id: 3,
    name: "원자 형성",
    timeRange: "38만 년",
    description: "전자가 원자핵 주변을 돌기 시작"
  }
];

// 모든 단계를 생성하는 함수
export function createAllStages() {
  return [
    createStage0_QuarkGluonPlasma(),
    createStage1_QuarkCombination(),
    createStage2_Nucleosynthesis(),
    createStage3_AtomFormation()
  ];
}
